go_intro.cheat:
// Quick Go cheat (practical)
// Tooling
// init module:   go mod init example.com/myapp
// tidy deps:     go mod tidy
// build:         go build -o bin/app ./...
// run quick:     go run ./cmd/app
// test:          go test ./... -v -race

// Filesystem layout
// cmd/<app>/main.go   -> application entrypoint
// pkg/<lib>           -> reusable packages

// Typical patterns
// - small interfaces at consumer side
// - prefer slices over arrays
// - check errors explicitly

examples.code:
package main
import "fmt"
func main(){ fmt.Println("Hello, Go") }

// go.mod
module example.com/myapp

go 1.20

go_syntax.cheat:
// Syntax cheat
// var <name> <type> = <value>
// short declaration: x := 10
// pointers: & to take address, * to dereference
// slices: make([]T, len, cap) or []T{...}
// zero values: default for each type

// Defer and loops
// defer closes resources, runs at function return
// for i, v := range s { ... }

examples.code:
x := 42
s := []int{1,2,3}
for i,v := range s { fmt.Println(i, v) }

// pointer receiver example
type Counter struct{ n int }
func (c *Counter) Inc(){ c.n++ }

// slice capacity growth
s := make([]int,0,4)
for i:=0;i<10;i++ { s = append(s,i) }

go_concurrency.cheat:
// Concurrency cheat
// goroutine: lightweight concurrent execution
// channel: typed conduit make(chan T)
// select: wait on multiple channel operations
// context: propagate cancellation and deadlines

// Patterns: pipelines, worker pools, fan-in/fan-out

examples.code:
// worker pool sketch
jobs := make(chan Job)
results := make(chan Result)
for w:=0; w<4; w++ { go func(){ for j := range jobs { results <- do(j) } }() }

// select with timeout
select {
case v := <-ch: return v
case <-time.After(2*time.Second): return errors.New("timeout")
}

go_interfaces.cheat:
// Interface cheat
// Define small consumer-side interfaces
// implicit implementation: no "implements" keyword
// use io.Reader/io.Writer idioms

// Prefer interface=behavior not data

examples.code:
// mock for tests
type fakeReader struct{ data []byte }
func (f fakeReader) Read(p []byte) (int,error){ return copy(p,f.data), io.EOF }

go_error.cheat:
// Error handling cheat
// return value, error; check explicitly
// wrap errors: fmt.Errorf("context: %w", err)
// inspect: errors.Is / errors.As

// Do not panic for normal errors; use panic for programmer errors only

examples.code:
// typed error example
type NotFoundError struct{ s string }
func (e NotFoundError) Error() string{ return e.s }

go_modules.cheat:
// Modules cheat
// go.mod: module path + go version
// go.sum: checksums
// go get module@version to pin
// go mod tidy to clean

// Use GOPROXY for caching and reproducible builds

go_memory.cheat:
// Memory cheat
// escape analysis decides heap vs stack
// reuse buffers: sync.Pool
// profile: net/http/pprof and go tool pprof

// Avoid unnecessary allocation in hot loops

examples.code:
// reduce allocations in loops
out := make([]byte,0,1024)
for _,s := range items { out = append(out, s... ) }

