go_networking.cheat:
// Networking cheat
// reuse single http.Client with configured Transport to reuse connections
// use context.WithTimeout for requests
// instrument endpoints and add timeouts on server

examples.code:
// basic server
http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request){ fmt.Fprintln(w, "hi") })
http.ListenAndServe(":8080", nil)

go_testing.cheat:
// Testing cheat
// table-driven tests, use t.Run for subtests
// use -race and -bench for benchmarks
// use httptest for HTTP handlers

go_context.cheat:
// Context cheat
// pass ctx as first parameter: func Do(ctx context.Context, ...)
// create: ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second); defer cancel()
// observe: select { case <-ctx.Done(): return ctx.Err() }

examples.code:
// HTTP request with context
req, _ := http.NewRequestWithContext(ctx, "GET", url, nil)
client.Do(req)

go_stdlib.cheat:
// Stdlib cheat
// key packages: io, bufio, encoding/json, net/http, time, context, sync
// prefer streaming APIs (io.Reader/io.Writer) over big buffers

examples.code:
// JSON stream decoder
var dec = json.NewDecoder(r)
for { var obj T; if err := dec.Decode(&obj); err==io.EOF { break } else if err!=nil { return err } }

go_cli.cheat:
// CLI cheat
// simple flags: flag package
// complex CLI: cobra + viper for config
// keep business logic outside main for testability

go_databases.cheat:
// Databases cheat
// use database/sql with context-aware methods (QueryContext)
// tune pool: db.SetMaxOpenConns, SetMaxIdleConns, SetConnMaxLifetime
// always parameterize queries

examples.code:
// transaction pattern
tx, _ := db.BeginTx(ctx, nil)
_, err := tx.ExecContext(ctx, "INSERT ...")
if err != nil { tx.Rollback(); return err }
if err := tx.Commit(); err != nil { return err }

go_security.cheat:
// Security cheat
// enforce TLS, validate inputs, use parameterized queries
// store secrets in vaults or environment variables, rotate frequently
// avoid logging secrets

examples.code:
// TLS server
srv := &http.Server{ Addr: ":443", TLSConfig: &tls.Config{ MinVersion: tls.VersionTLS12 } }
_ = srv.ListenAndServeTLS("cert.pem","key.pem")

// Validate JSON input
var req Request
if err := json.NewDecoder(r.Body).Decode(&req); err != nil { http.Error(w, "bad request", 400); return }

// use prepared stmt
stmt, _ := db.PrepareContext(ctx, "INSERT INTO x (a) VALUES ($1)")
stmt.ExecContext(ctx, v)

